{"cells":[{"cell_type":"code","source":["# Mount Google Drive to access analysis files.\n","\n","from google.colab import drive\n","drive.mount('/content/drive')\n","\n","dir_path = '/content/drive/MyDrive/Personal/Sues/'"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"FcxwovpXbN7S","executionInfo":{"status":"ok","timestamp":1761631648880,"user_tz":-660,"elapsed":27635,"user":{"displayName":"Tomer","userId":"10873557234236150514"}},"outputId":"932f5c49-e630-4e7e-a01f-a91e73769812"},"execution_count":null,"outputs":[{"output_type":"stream","name":"stdout","text":["Mounted at /content/drive\n"]}]},{"cell_type":"code","source":["import pandas as pd\n","import re\n","import sys\n","from tqdm import tqdm"],"metadata":{"id":"QCMh1pYsbNwX"},"execution_count":null,"outputs":[]},{"cell_type":"code","source":["# --- 1. CONFIGURATION ---\n","\n","# Add all files you want to fix here\n","INPUT_FILES_TO_FIX = [\n","    dir_path + 'term_analysis_strict.csv',\n","    dir_path + 'term_analysis_sensitive.csv' # It can fix both!\n","]\n","OUTPUT_FILE_SUFFIX = '_FIXED.csv'\n","\n","# --- 2. CORE FUNCTIONS ---\n","\n","def find_context(full_text, term, is_strict_search):\n","    \"\"\"\n","    Robust context-finding logic.\n","    Splits text into sentences (respecting newlines) and finds matches using word boundaries.\n","    \"\"\"\n","    if not isinstance(full_text, str):\n","        return \"CONTEXT_FIX_ERROR: Invalid text\"\n","\n","    # --- FIX 1: Treat Newlines as Sentence Breaks ---\n","    # Before squashing spaces, replace newlines with a period to preserve list/header structure.\n","    # We replace \\n with \". \" so \"Title\\nSubtitle\" becomes \"Title. Subtitle.\"\n","    temp_text = str(full_text).replace('\\n', '. ')\n","\n","    # Now normalize whitespace (tabs, double spaces -> single space)\n","    clean_text = re.sub(r'\\s+', ' ', temp_text).strip()\n","\n","    # --- FIX 2: Improved Sentence Splitting ---\n","    # We use a slightly more comprehensive split pattern.\n","    # It splits on [.?!] followed by space, or end of string.\n","    sentences = re.split(r'(?<!\\w\\.\\w.)(?<![A-Z][a-z]\\.)(?<=\\.|\\?|\\!)\\s+', clean_text)\n","\n","    # --- FIX 3: Robust Search Logic ---\n","    finder_func = None\n","    if is_strict_search:\n","        try:\n","            # Use \\b (Word Boundary) for strict matching.\n","            # This matches \"Midwifery\" in: \"Nursing/Midwifery\", \"(Midwifery)\", \"Midwifery.\"\n","            escaped_term = re.escape(str(term))\n","            regex_pattern = r\"\\b\" + escaped_term + r\"\\b\"\n","\n","            finder_func = lambda sentence: re.search(regex_pattern, sentence, re.IGNORECASE)\n","        except Exception as e:\n","            print(f\"Regex error for term '{term}': {e}\", file=sys.stderr)\n","            return f\"CONTEXT_FIX_ERROR: Regex fail for {term}\"\n","    else:\n","        # Sensitive logic remains simple substring match\n","        lower_term = str(term).lower()\n","        finder_func = lambda sentence: lower_term in sentence.lower()\n","\n","    # 4. Find all matching sentences\n","    context_sentences = []\n","    for s in sentences:\n","        s = s.strip()\n","        # Avoid empty strings or pure punctuation\n","        if len(s) > 1 and finder_func(s):\n","            context_sentences.append(s)\n","\n","    if context_sentences:\n","        return \" | \".join(context_sentences)\n","    else:\n","        return \"CONTEXT_FIX_FAILED: No sentence match found\"\n","\n","# --- 3. MAIN EXECUTION ---\n","\n","def main():\n","    \"\"\"\n","    Main script execution.\n","    1. Loops through each file in INPUT_FILES_TO_FIX.\n","    2. [NEW] Builds a text cache *from the CSV itself* (no network).\n","    3. Re-processes each original file, row by row.\n","    4. Re-applies the correct context-finding logic (Strict or Sensitive).\n","    5. Saves a new \"_FIXED.csv\" file.\n","    \"\"\"\n","    print(\"Starting OFFLINE context-fixing script...\")\n","\n","    files_to_process = []\n","\n","    # --- Pass 1: Load CSVs into memory ---\n","    print(\"Loading CSV files...\")\n","    for filename in INPUT_FILES_TO_FIX:\n","        try:\n","            df = pd.read_csv(filename)\n","            if 'Unit Link' not in df.columns or 'Term Found' not in df.columns or 'Context (Sentences)' not in df.columns:\n","                print(f\"  [!] Skipping {filename}: missing 'Unit Link', 'Term Found', or 'Context (Sentences)' column.\", file=sys.stderr)\n","                continue\n","\n","            files_to_process.append((filename, df))\n","            print(f\"  > Loaded {filename} with {len(df)} rows.\")\n","\n","        except FileNotFoundError:\n","            print(f\"  [!] Skipping {filename}: File not found.\", file=sys.stderr)\n","        except Exception as e:\n","            print(f\"  [!] Skipping {filename}: Could not read file. Error: {e}\", file=sys.stderr)\n","\n","    if not files_to_process:\n","        print(\"No valid input files found. Exiting.\")\n","        return\n","\n","    # --- Pass 2: Process each file and fix context ---\n","    for filename, df in files_to_process:\n","        print(f\"\\nProcessing {filename}...\")\n","\n","        # Determine if this is a strict or sensitive file\n","        is_strict = 'strict' in filename.lower()\n","        analysis_type = \"Strict\" if is_strict else \"Sensitive\"\n","        print(f\"  > Applying {analysis_type} context-finding logic.\")\n","\n","        # [NEW] Build the text cache from the 'Context (Sentences)' column\n","        print(\"  > Building text cache from 'Context (Sentences)' column...\")\n","        try:\n","            # Group by 'Unit Link' and take the first 'Context (Sentences)' entry\n","            # (since they are all the same full text for that unit)\n","            text_cache = df.groupby('Unit Link')['Context (Sentences)'].first().to_dict()\n","            print(f\"  > Cache built with text for {len(text_cache)} unique units.\")\n","        except Exception as e:\n","            print(f\"  [!] Failed to build text cache: {e}\", file=sys.stderr)\n","            continue # Skip this file\n","\n","        new_context_list = []\n","\n","        # [NEW] This loop is now much faster as it only references the cache\n","        for index, row in tqdm(df.iterrows(), total=df.shape[0], desc=f\"Fixing context in {filename}\"):\n","            # Get the full text from our new cache\n","            unit_text = text_cache.get(row['Unit Link'])\n","\n","            if not unit_text:\n","                new_context_list.append(\"CONTEXT_FIX_ERROR: Text not in cache\")\n","                continue\n","\n","            # Find the new, correct context\n","            new_context = find_context(unit_text, str(row['Term Found']), is_strict)\n","            new_context_list.append(new_context)\n","\n","        # All rows processed, update the DataFrame column\n","        df['Context (Sentences)'] = new_context_list\n","\n","        # Save the fixed DataFrame\n","        try:\n","            output_filename = filename.replace('.csv', OUTPUT_FILE_SUFFIX)\n","            df.to_csv(output_filename, index=False, encoding='utf-8')\n","            print(f\"  > Successfully saved fixed file to '{output_filename}'\")\n","        except Exception as e:\n","            print(f\"  [!] Failed to save new file. Error: {e}\", file=sys.stderr)\n","\n","    print(\"\\nContext fixing process is complete.\")\n","\n","if __name__ == \"__main__\":\n","    main()"],"outputs":[{"output_type":"stream","name":"stdout","text":["Starting OFFLINE context-fixing script...\n","Loading CSV files...\n","  > Loaded /content/drive/MyDrive/Personal/Sues/term_analysis_strict.csv with 252 rows.\n","  > Loaded /content/drive/MyDrive/Personal/Sues/term_analysis_sensitive.csv with 3074 rows.\n","\n","Processing /content/drive/MyDrive/Personal/Sues/term_analysis_strict.csv...\n","  > Applying Strict context-finding logic.\n","  > Building text cache from 'Context (Sentences)' column...\n","  > Cache built with text for 107 unique units.\n"]},{"output_type":"stream","name":"stderr","text":["Fixing context in /content/drive/MyDrive/Personal/Sues/term_analysis_strict.csv: 100%|██████████| 252/252 [00:00<00:00, 1263.89it/s]\n"]},{"output_type":"stream","name":"stdout","text":["  > Successfully saved fixed file to '/content/drive/MyDrive/Personal/Sues/term_analysis_strict_FIXED.csv'\n","\n","Processing /content/drive/MyDrive/Personal/Sues/term_analysis_sensitive.csv...\n","  > Applying Sensitive context-finding logic.\n","  > Building text cache from 'Context (Sentences)' column...\n","  > Cache built with text for 559 unique units.\n"]},{"output_type":"stream","name":"stderr","text":["Fixing context in /content/drive/MyDrive/Personal/Sues/term_analysis_sensitive.csv: 100%|██████████| 3074/3074 [00:02<00:00, 1466.55it/s]\n"]},{"output_type":"stream","name":"stdout","text":["  > Successfully saved fixed file to '/content/drive/MyDrive/Personal/Sues/term_analysis_sensitive_FIXED.csv'\n","\n","Context fixing process is complete.\n"]}],"execution_count":null,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"I4sFu5VDbEPn","executionInfo":{"status":"ok","timestamp":1761631732725,"user_tz":-660,"elapsed":5066,"user":{"displayName":"Tomer","userId":"10873557234236150514"}},"outputId":"66fb6134-8bd6-4500-e910-154fb3d4dedd"}}],"metadata":{"colab":{"provenance":[]},"kernelspec":{"display_name":"Python 3","name":"python3"}},"nbformat":4,"nbformat_minor":0}